import{_ as t,c as a,o as s,ag as r}from"./chunks/framework.By5zrZ8k.js";const u=JSON.parse('{"title":"Neo Console","description":"","frontmatter":{},"headers":[],"relativePath":"projects/mlai/neo/core/m-console.md","filePath":"projects/mlai/neo/core/m-console.md","lastUpdated":1773130255000}'),o={name:"projects/mlai/neo/core/m-console.md"};function n(i,e,l,c,d,h){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="neo-console" tabindex="-1">Neo Console <a class="header-anchor" href="#neo-console" aria-label="Permalink to &quot;Neo Console&quot;">​</a></h1><h2 id="access-the-web-management-interface" tabindex="-1">Access the web management interface <a class="header-anchor" href="#access-the-web-management-interface" aria-label="Permalink to &quot;Access the web management interface&quot;">​</a></h2><p>The Neo Console is a web-based management interface that connects to the API service. It can be accessed by navigating to <code>http://&lt;server-ip&gt;:8081</code> in your web browser, where <code>&lt;server-ip&gt;</code> is the IP address of the server where NetApp Project Neo is deployed. If you are using ingress, use the appropriate URL configured for access.</p><p>If the web interface is not accessible, ensure that the API service is running on port 8000 and that there are no firewall rules blocking access to port 8081.</p><p>On first access, you will be prompted to log in. Use the default credentials provided during installation. It is highly recommended to change the default password upon first login for security purposes. If you have forgotten your password, run the following command to retrieve the auto-generated admin password:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --location</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://&lt;server-ip&gt;:8000/api/v1/setup/initial-credentials&#39;</span></span></code></pre></div><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The above command will only work if the admin user has never logged in before. If the admin user has logged in previously, you will need to reset the password via the API or database.</p></div><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>The console provides a full-text search interface for querying indexed content across all configured shares. Search features include:</p><ul><li><strong>Full-text search</strong>: Search across all extracted document content using natural language queries. Results are ranked by relevance using PostgreSQL GIN-indexed search vectors.</li><li><strong>Filters</strong>: Narrow results by share, file type, date range, or NER entity tags.</li><li><strong>File preview</strong>: View extracted content and metadata for any search result.</li><li><strong>Export</strong>: Download search results for further analysis.</li></ul><h2 id="operations" tabindex="-1">Operations <a class="header-anchor" href="#operations" aria-label="Permalink to &quot;Operations&quot;">​</a></h2><p>The console provides an operations dashboard for managing Neo services and monitoring system health:</p><ul><li><strong>Share management</strong>: Add, edit, and remove SMB shares. Configure crawl schedules, include/exclude patterns, and authentication settings.</li><li><strong>Crawl monitoring</strong>: View active crawls, progress, file counts, and error logs in real time.</li><li><strong>Task queue</strong>: Monitor the worker task queue, view pending and completed jobs, and retry failed tasks.</li><li><strong>NER status</strong>: View Named Entity Recognition processing status and results per share.</li><li><strong>Graph sync</strong>: Monitor Microsoft 365 Copilot connector sync status, including upload progress and errors.</li><li><strong>System health</strong>: View service status, database size, and resource utilization.</li><li><strong>User management</strong>: Create, edit, and deactivate user accounts and manage roles.</li></ul>',13)])])}const g=t(o,[["render",n]]);export{u as __pageData,g as default};
